+        let tasks: Vec<
+            Box<dyn FnOnce(Cx) -> std::pin::Pin<Box<dyn Future<Output = usize> + Send>> + Send>,
+        > = (0..4_usize)
+            .map(|i| {
+                let active = Arc::clone(&active);
+                let peak = Arc::clone(&peak);
+                let closure: Box<
+                    dyn FnOnce(Cx) -> std::pin::Pin<Box<dyn Future<Output = usize> + Send>> + Send,
