+                    Box::pin(async move {
+                        let now_active = active.fetch_add(1, Ordering::SeqCst) + 1;
+                        record_peak(&peak, now_active);
+                        crate::runtime_compat::sleep(Duration::from_millis(10)).await;
+                        active.fetch_sub(1, Ordering::SeqCst);
+                        i
+                    })
+                });
+                closure
+            })
+            .collect();
